1	import { useEffect, useState } from 'preact/hooks';
2	import { useLLM } from '../llm';
3	import {
4	  applyImportFromFile,
5	  downloadExport,
6	  exportPayload,
7	  formatImportMessage,
8	} from './Workouts/logic/exportImport';
9	import { clearAll } from './Workouts/state';
10	
11	const MODE_STORAGE_KEY = 'flux_mode';
12	type Mode = 'dark' | 'light';
13	
14	function detectInitialMode(): Mode {
15	  if (typeof window === 'undefined') return 'dark';
16	  try {
17	    const stored = window.localStorage.getItem(MODE_STORAGE_KEY);
18	    if (stored === 'dark' || stored === 'light') return stored;
19	  } catch {
20	    // localStorage unavailable
21	  }
22	  return window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark';
23	}
24	
25	function applyMode(mode: Mode): void {
26	  document.documentElement.setAttribute('data-mode', mode);
27	  try {
28	    window.localStorage.setItem(MODE_STORAGE_KEY, mode);
29	  } catch {
30	    // ignore
31	  }
32	}
33	
34	export function Settings() {
35	  const { available } = useLLM();
36	  const [mode, setMode] = useState<Mode>(detectInitialMode);
37	  const [importMessage, setImportMessage] = useState<string | null>(null);
38	
39	  useEffect(() => {
40	    applyMode(mode);
41	  }, [mode]);
42	
43	  async function handleExport() {
44	    const payload = await exportPayload();
45	    downloadExport(payload);
46	  }
47	
48	  async function handleImport(e: Event) {
49	    const input = e.target as HTMLInputElement;
50	    const file = input.files?.[0];
51	    input.value = '';
52	    if (!file) return;
53	    try {
54	      const result = await applyImportFromFile(file, { applyState: true });
55	      setImportMessage(formatImportMessage(result));
56	    } catch (err) {
57	      setImportMessage(
58	        'Import failed: ' + (err instanceof Error ? err.message : 'unknown error'),
59	      );
60	    }
61	  }
62	
63	  async function handleReset() {
64	    if (!confirm('Reset all progress? This clears day count, exercise log, and loaded program.')) return;
65	    try {
66	      await clearAll();
67	      setImportMessage('Reset complete.');
68	    } catch (err) {
69	      setImportMessage(
70	        'Reset failed: ' + (err instanceof Error ? err.message : 'unknown error'),
71	      );
72	    }
73	  }
74	
75	  return (
76	    <section class="mx-auto max-w-md space-y-5">
77	      <header class="flex flex-col items-center gap-1 pt-2 text-center">
78	        <h1 class="text-sm font-medium uppercase tracking-[0.28em] text-flux-text-primary">
79	          Settings
80	        </h1>
81	        <p class="text-[10px] uppercase tracking-[0.2em] text-flux-text-tertiary">
82	          Preferences & data
83	        </p>
84	      </header>
85	
86	      <div class="rounded-[2rem] bg-flux-card p-6 shadow-flux-card">
87	        <h2 class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary">
88	          Appearance
89	        </h2>
90	        <div class="mt-4 inline-flex rounded-full bg-flux-soft p-1">
91	          {(['dark', 'light'] as const).map((m) => (
92	            <button
93	              key={m}
94	              type="button"
95	              class={
96	                'rounded-full px-4 py-1.5 text-[11px] font-medium uppercase tracking-[0.18em] transition-all ' +
97	                (mode === m
98	                  ? 'bg-flux-accent text-flux-accent-fg shadow-flux-soft'
99	                  : 'text-flux-text-secondary hover:text-flux-text-primary')
100	              }
101	              data-mode={m}
102	              onClick={() => setMode(m)}
103	            >
104	              {m}
105	            </button>
106	          ))}
107	        </div>
108	      </div>
109	
110	      <div class="rounded-[2rem] bg-flux-card p-6 shadow-flux-card">
111	        <h2 class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary">
112	          LLM provider
113	        </h2>
114	        <p class="mt-3 text-sm text-flux-text-secondary">
115	          {available ? 'Configured' : 'Not configured'}
116	        </p>
117	      </div>
118	
119	      <div class="rounded-[2rem] bg-flux-card p-6 shadow-flux-card">
120	        <h2 class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary">
121	          Data
122	        </h2>
123	        <div class="mt-4 flex flex-wrap items-center gap-2">
124	          <button
125	            type="button"
126	            class="rounded-full bg-flux-soft px-4 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-text-secondary transition-colors hover:text-flux-text-primary"
127	            onClick={handleExport}
128	            data-testid="export-btn"
129	          >
130	            Export
131	          </button>
132	          <label
133	            class="cursor-pointer rounded-full bg-flux-soft px-4 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-text-secondary transition-colors hover:text-flux-text-primary"
134	            data-testid="import-backup-label"
135	          >
136	            Import Backup
137	            <input
138	              type="file"
139	              accept="application/json,.json"
140	              class="hidden"
141	              onChange={handleImport}
142	              data-testid="import-input"
143	            />
144	          </label>
145	        </div>
146	        {importMessage && (
147	          <div
148	            class="mt-4 flex items-start justify-between gap-2 rounded-2xl bg-flux-soft px-4 py-3 text-xs text-flux-text-secondary"
149	            data-testid="backup-import-message"
150	          >
151	            <span class="flex-1">{importMessage}</span>
152	            <button
153	              type="button"
154	              onClick={() => setImportMessage(null)}
155	              class="shrink-0 text-flux-text-tertiary hover:text-flux-text-primary"
156	              aria-label="Dismiss"
157	              data-testid="backup-import-message-dismiss"
158	            >
159	              ×
160	            </button>
161	          </div>
162	        )}
163	
164	        <div class="mt-5 border-t border-flux-border pt-4">
165	          <p class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-danger">
166	            Danger zone
167	          </p>
168	          <button
169	            type="button"
170	            class="mt-3 rounded-full bg-flux-soft px-4 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-danger transition-opacity hover:opacity-80"
171	            onClick={handleReset}
172	            data-testid="reset-btn"
173	          >
174	            Reset all progress
175	          </button>
176	        </div>
177	      </div>
178	    </section>
179	  );
180	}
