329	        <button
330	          type="button"
331	          class="rounded-full bg-flux-accent px-5 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-accent-fg shadow-flux-soft transition-opacity hover:opacity-90"
332	          onClick={nextDay}
333	          data-testid="next-day"
334	        >
335	          Complete & Advance →
336	        </button>
337	      </div>
338	
339	      {importMessage && (
340	        <div
341	          class="flex items-start justify-between gap-2 rounded-2xl bg-flux-card px-4 py-3 text-xs text-flux-text-secondary shadow-flux-soft"
342	          data-testid="program-import-message"
343	        >
344	          <span class="flex-1">{importMessage}</span>
345	          <button
346	            type="button"
347	            onClick={() => setImportMessage(null)}
348	            class="shrink-0 text-flux-text-tertiary hover:text-flux-text-primary"
349	            aria-label="Dismiss"
350	            data-testid="program-import-message-dismiss"
351	          >
352	            ×
353	          </button>
354	        </div>
355	      )}
356	
357	      {video && (
358	        <VideoModal
359	          videoId={video.videoId}
360	          start={video.start}
361	          onClose={() => setVideo(null)}
362	        />
363	      )}
364	    </section>
365	  );
366	}
