                equipmentRequired: ex.equipmentRequired ?? [],
                equipmentAlternatives: ex.equipmentAlternatives,
                usesWeight: ex.usesWeight,
              };
              const allowedWeights =
                ex.equipmentRequired !== undefined
                  ? allowedWeightsForExercise(exShape as never, inventory)
                  : null;
