          class="flex items-start justify-between gap-2 rounded-2xl bg-flux-card px-4 py-3 text-xs text-flux-text-secondary shadow-flux-soft"
          data-testid="program-import-message"
        >
          <span class="flex-1">{importMessage}</span>
